(function(){
  'use strict';
  function products(){return (window.data&&Array.isArray(data.products))?data.products:[]}
  function getProduct(id){return typeof window.product==='function'?product(id):products().find(function(p){return p.id===id})}
  function isBundle(p){return !!(p&&((p.bundleEnabled==='Yes'||p.bundleEnabled===true)||String(p.productType||'').toLowerCase()==='bundle')&&Array.isArray(p.bundleItems)&&p.bundleItems.length)}
  function items(p){return Array.isArray(p&&p.bundleItems)?p.bundleItems.filter(function(x){return x&&x.productId&&Number(x.qty||0)>0}):[]}
  function esc(v){return typeof window.escapeHtml==='function'?escapeHtml(String(v==null?'':v)):String(v==null?'':v).replace(/[&<>"']/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]})}
  function cash(v){return typeof window.money==='function'?money(Number(v||0)):'£'+Number(v||0).toFixed(2)}
  function componentTotals(p){return items(p).reduce(function(t,row){var c=getProduct(row.productId);if(!c)return t;var q=Number(row.qty||0);t.cost+=Number(c.cost||0)*q;t.rrp+=Number(c.rrp||0)*q;t.count+=q;return t},{cost:0,rrp:0,count:0})}
  function bundleAvailability(p){var list=items(p);if(!list.length)return {onHand:0,allocated:0,available:0};var values=list.map(function(row){var s=window.__poolShedOriginalProductStockSummary?window.__poolShedOriginalProductStockSummary(row.productId):productStockSummary(row.productId);var q=Math.max(1,Number(row.qty||1));return {on:Math.floor(Number(s.onHand||0)/q),av:Math.floor(Number(s.available||0)/q)}});return {onHand:Math.min.apply(null,values.map(function(x){return x.on})),allocated:0,available:Math.min.apply(null,values.map(function(x){return x.av}))}}
  window.PoolShedBundles={isBundle:isBundle,items:items,totals:componentTotals,availability:bundleAvailability};

  if(typeof window.productStockSummary==='function'){
    window.__poolShedOriginalProductStockSummary=window.productStockSummary;
    window.productStockSummary=function(id){var p=getProduct(id);return isBundle(p)?bundleAvailability(p):window.__poolShedOriginalProductStockSummary(id)};
  }
  if(typeof window.isNonStockSalesLine==='function'){
    var originalNonStock=window.isNonStockSalesLine;
    window.isNonStockSalesLine=function(line){return !!(line&&(line.lineType==='bundle'||line.bundleRole==='head'))||originalNonStock(line)};
  }

  function bundleTab(p){
    var totals=componentTotals(p), list=items(p), enabled=(p.bundleEnabled==='Yes'||p.bundleEnabled===true||String(p.productType||'').toLowerCase()==='bundle');
    var rows=list.map(function(row){var c=getProduct(row.productId);if(!c)return '';return '<div class="bundle-component-row" data-bundle-component-row="'+esc(c.id)+'"><div class="identity"><strong>'+esc(c.name)+'</strong><span>'+esc(c.sku)+' · '+esc(c.supplier||'No supplier')+'</span></div><label>Qty<input type="number" min="1" step="1" value="'+Number(row.qty||1)+'" data-bundle-component-qty="'+esc(c.id)+'"></label><div class="component-cost"><span class="muted">Cost</span><strong>'+cash(Number(c.cost||0)*Number(row.qty||1))+'</strong></div><div class="component-rrp"><span class="muted">RRP</span><strong>'+cash(Number(c.rrp||0)*Number(row.qty||1))+'</strong></div><button type="button" class="danger" data-remove-bundle-component="'+esc(c.id)+'" aria-label="Remove '+esc(c.name)+'">×</button></div>'}).join('');
    return '<div class="bundle-builder" data-bundle-builder="'+esc(p.id)+'"><section class="bundle-hero"><div><span class="eyebrow">POOL BROS BUNDLE ENGINE</span><h3>Build a sellable bundle from live catalogue products</h3><p>The bundle is the customer-facing head product. Components remain the stock-controlled items used for allocation, picking, goods-in and purchasing.</p></div><span class="bundle-status">'+(enabled?'Bundle active':'Not active')+'</span></section><div class="bundle-grid"><section class="bundle-card"><h3>Bundle components</h3><p class="muted">Search and add products. Quantities are stored against this head product.</p><label>Find a component<input data-bundle-search="'+esc(p.id)+'" autocomplete="off" placeholder="Search product, SKU, supplier SKU or barcode"></label><div class="bundle-search-results" data-bundle-search-results="'+esc(p.id)+'"></div><div class="bundle-component-list" data-bundle-component-list="'+esc(p.id)+'">'+(rows||'<div class="empty-state"><strong>No components added</strong><p>Search above to build this bundle.</p></div>')+'</div></section><aside class="bundle-card"><h3>Bundle rules and pricing</h3><label>Bundle status<select data-bundle-enabled="'+esc(p.id)+'"><option '+(enabled?'selected':'')+'>Yes</option><option '+(!enabled?'selected':'')+'>No</option></select></label><label>Bundle SKU / reference<input data-bundle-reference="'+esc(p.id)+'" value="'+esc(p.bundleReference||p.sku||'')+'"></label><label>Sell price rule<select data-bundle-price-mode="'+esc(p.id)+'"><option value="sum" '+((p.bundlePriceMode||'sum')==='sum'?'selected':'')+'>Add component RRPs together</option><option value="manual" '+(p.bundlePriceMode==='manual'?'selected':'')+'>Use manual bundle RRP</option></select></label><label>Manual bundle RRP<input type="number" min="0" step="0.01" data-bundle-manual-rrp="'+esc(p.id)+'" value="'+Number(p.bundleManualRrp||p.rrp||0).toFixed(2)+'"></label><label>Availability rule<select data-bundle-availability-rule="'+esc(p.id)+'"><option '+((p.bundleAvailabilityRule||'Lowest component availability')==='Lowest component availability'?'selected':'')+'>Lowest component availability</option><option '+(p.bundleAvailabilityRule==='Do not sell when incomplete'?'selected':'')+'>Do not sell when incomplete</option></select></label><div class="bundle-summary"><div><span>Component lines</span><strong>'+list.length+'</strong></div><div><span>Total units</span><strong>'+totals.count+'</strong></div><div><span>Combined cost</span><strong>'+cash(totals.cost)+'</strong></div><div><span>Calculated RRP</span><strong>'+cash(totals.rrp)+'</strong></div><div><span>Bundle available</span><strong>'+bundleAvailability(p).available+'</strong></div><div><span>Margin</span><strong>'+cash(((p.bundlePriceMode==='manual'?Number(p.bundleManualRrp||0):totals.rrp)-totals.cost))+'</strong></div></div><div class="bundle-actions"><button type="button" class="secondary" data-recalculate-bundle="'+esc(p.id)+'">Recalculate</button><button type="button" data-save-bundle="'+esc(p.id)+'">Save bundle</button></div></aside></div></div>';
  }
  if(typeof window.productProfileTabContent==='function'){
    var oldTab=window.productProfileTabContent;
    window.productProfileTabContent=function(p,summary){if(window.productTab==='bundle')return bundleTab(p);return oldTab(p,summary)};
  }

  function currentBuilderProduct(el){var root=el.closest('[data-bundle-builder]');return root?getProduct(root.dataset.bundleBuilder):null}
  function refresh(){if(typeof window.render==='function')render()}
  document.addEventListener('input',function(e){
    var input=e.target.closest('[data-bundle-search]');if(!input)return;var p=getProduct(input.dataset.bundleSearch),box=document.querySelector('[data-bundle-search-results="'+input.dataset.bundleSearch+'"]');if(!p||!box)return;var q=String(input.value||'').toLowerCase().trim();if(!q){box.innerHTML='';return}var existing=new Set(items(p).map(function(x){return x.productId}));var matches=products().filter(function(x){if(!x||x.id===p.id||x.hiddenFromCatalogue||x.deleted||existing.has(x.id)||isBundle(x))return false;var hay=[x.name,x.parentName,x.sku,x.supplierSku,x.barcode,x.supplier,x.category].join(' ').toLowerCase();return q.split(/\s+/).every(function(t){return hay.indexOf(t)>=0})}).slice(0,8);box.innerHTML=matches.map(function(x){return '<button type="button" class="bundle-search-result" data-add-bundle-component="'+esc(x.id)+'"><span><strong>'+esc(x.name)+'</strong><span class="muted">'+esc(x.sku)+' · '+esc(x.supplier||'No supplier')+'</span></span><strong>'+cash(x.rrp||0)+'</strong></button>'}).join('')||'<div class="empty-state"><strong>No matching components</strong></div>';
  });
  document.addEventListener('click',function(e){
    var add=e.target.closest('[data-add-bundle-component]');if(add){var p=currentBuilderProduct(add);if(!p)return;p.bundleItems=items(p);p.bundleItems.push({productId:add.dataset.addBundleComponent,qty:1});saveBundle(p,false);refresh();return}
    var remove=e.target.closest('[data-remove-bundle-component]');if(remove){var rp=currentBuilderProduct(remove);if(!rp)return;rp.bundleItems=items(rp).filter(function(x){return x.productId!==remove.dataset.removeBundleComponent});saveBundle(rp,false);refresh();return}
    var recalc=e.target.closest('[data-recalculate-bundle]');if(recalc){var cp=getProduct(recalc.dataset.recalculateBundle);if(cp){saveBundle(cp,true);refresh()}return}
    var save=e.target.closest('[data-save-bundle]');if(save){var sp=getProduct(save.dataset.saveBundle);if(sp){saveBundle(sp,true);if(typeof window.toast==='function')toast('Bundle saved and connected across sales, stock and purchasing.');refresh()}return}
    var removeLine=e.target.closest('[data-remove-sales-line]');if(removeLine){var parts=removeLine.dataset.removeSalesLine.split('|'),order=typeof window.salesOrder==='function'?salesOrder(parts[0]):null,line=order&&order.lines.find(function(x){return x.productId===parts[1]});if(line&&line.bundleRole==='head'){e.preventDefault();e.stopImmediatePropagation();if(!confirm('Remove this bundle and all of its component lines from '+order.id+'?'))return;var key=line.bundleInstanceId;order.lines=order.lines.filter(function(x){return x.bundleInstanceId!==key});saveAppData();toast('Bundle removed from '+order.id+'.');refresh()}}
  },true);
  document.addEventListener('change',function(e){var q=e.target.closest('[data-bundle-component-qty]');if(q){var p=currentBuilderProduct(q);if(!p)return;var row=items(p).find(function(x){return x.productId===q.dataset.bundleComponentQty});if(row)row.qty=Math.max(1,Math.floor(Number(q.value||1)));saveBundle(p,false);refresh()}});

  function saveBundle(p,fromForm){
    if(fromForm){var id=p.id,read=function(sel){var n=document.querySelector(sel+'[data-bundle-enabled="'+id+'"],'+sel+'[data-bundle-reference="'+id+'"]');return n};var enabled=document.querySelector('[data-bundle-enabled="'+id+'"]'),ref=document.querySelector('[data-bundle-reference="'+id+'"]'),mode=document.querySelector('[data-bundle-price-mode="'+id+'"]'),manual=document.querySelector('[data-bundle-manual-rrp="'+id+'"]'),rule=document.querySelector('[data-bundle-availability-rule="'+id+'"]');if(enabled)p.bundleEnabled=enabled.value;if(ref)p.bundleReference=ref.value;if(mode)p.bundlePriceMode=mode.value;if(manual)p.bundleManualRrp=Number(manual.value||0);if(rule)p.bundleAvailabilityRule=rule.value}
    p.bundleItems=items(p);p.productType=(p.bundleEnabled==='Yes'?'Bundle':p.productType);p.stockTracked=p.bundleEnabled==='Yes'?false:p.stockTracked;var totals=componentTotals(p);p.cost=totals.cost;if((p.bundlePriceMode||'sum')==='sum')p.rrp=totals.rrp;else p.rrp=Number(p.bundleManualRrp||p.rrp||0);p.bundleComponents=p.bundleItems.map(function(x){var c=getProduct(x.productId);return (c?c.sku:x.productId)+' | '+x.qty}).join('\n');p.updatedAt=new Date().toISOString();if(typeof window.saveAppData==='function')saveAppData();
  }

  function addBundleToSalesOrder(order,p,qty){var instance='BND-'+Date.now().toString(36)+'-'+Math.random().toString(36).slice(2,6);order.lines.push({productId:p.id,qty:qty,allocated:qty,picked:0,packed:0,lineType:'bundle',bundleRole:'head',bundleInstanceId:instance,unitPrice:Number(p.rrp||0),unitCost:Number(p.cost||0),description:p.name});items(p).forEach(function(row){var c=getProduct(row.productId);if(!c)return;order.lines.push({productId:c.id,qty:Number(row.qty||1)*qty,allocated:0,picked:0,packed:0,unitPrice:0,unitCost:Number(c.cost||0),bundleRole:'component',bundleInstanceId:instance,bundleParentId:p.id,bundleParentSku:p.sku,bundleParentName:p.name})});order.status='Needs Review';saveAppData();toast(p.sku+' bundle added with '+items(p).length+' component lines.');refresh()}
  if(typeof window.addProductToSalesOrder==='function'){
    var oldAddSO=window.addProductToSalesOrder;window.addProductToSalesOrder=function(orderId){var search=document.getElementById('salesOrderProductSearch'),p=search&&getProduct(search.dataset.selectedProductId||'');if(!isBundle(p))return oldAddSO(orderId);var order=salesOrder(orderId),qty=Math.max(1,Math.floor(Number((document.getElementById('salesOrderProductQty')||{}).value||1)));if(!order)return;addBundleToSalesOrder(order,p,qty)};
  }

  function addPoLine(po,p,qty,bundle){var existing=(po.lines||[]).find(function(x){return x.productId===p.id&&!x.salesOrderId});if(existing)existing.qty=Number(existing.qty||0)+qty;else po.lines.push({productId:p.id,qty:qty,received:0,supplierSku:p.supplierSku||'',unitCost:Number(p.cost||0),orderedDate:typeof todayIso==='function'?todayIso():'',dueDate:po.due,leadTimeDays:typeof defaultSupplierLeadTime==='function'?defaultSupplierLeadTime(p.supplier):3,chaseStatus:'Waiting',nextChaseDate:typeof todayIso==='function'?todayIso():'',supplierNotes:'Component of bundle '+bundle.sku,bundleParentId:bundle.id,bundleParentSku:bundle.sku,bundleParentName:bundle.name})}
  if(typeof window.addSelectedProductToPurchaseOrder==='function'){
    var oldAddPO=window.addSelectedProductToPurchaseOrder;window.addSelectedProductToPurchaseOrder=function(poId){var search=document.getElementById('poProductSearch'),p=search&&getProduct(search.dataset.selectedProductId||'');if(!isBundle(p))return oldAddPO(poId);var po=purchaseOrderById(poId),qty=Math.max(1,Math.floor(Number((document.getElementById('poProductQty')||{}).value||1)));if(!po)return;var groups={};items(p).forEach(function(row){var c=getProduct(row.productId);if(!c)return;var supplier=c.supplier||'Supplier to confirm';(groups[supplier]||(groups[supplier]=[])).push({p:c,qty:Number(row.qty||1)*qty})});Object.keys(groups).forEach(function(supplier){var target=po;if(po.supplier&&po.supplier!=='Supplier to confirm'&&po.supplier!==supplier){var id=nextPurchaseOrderId();target={id:id,supplier:supplier,status:'Draft - Review',due:po.due,source:'Bundle component split',reviewStatus:'Needs review',supplierEmailStatus:'Blocked until reviewed',originalSalesOrderId:po.originalSalesOrderId||'',customerId:po.customerId||'',customerName:po.customerName||'',customerShipTo:po.customerShipTo||'',lines:[],bundleSource:{productId:p.id,sku:p.sku,name:p.name}};data.purchaseOrders.push(target)}else if(!po.supplier||po.supplier==='Supplier to confirm')po.supplier=supplier;groups[supplier].forEach(function(x){addPoLine(target,x.p,x.qty,p)})});saveAppData();toast(p.sku+' exploded into '+items(p).length+' purchasing component lines.');refresh()};
  }

  function decorateRows(){document.querySelectorAll('.order-lines-table tbody tr').forEach(function(tr){var code=(tr.cells[2]&&tr.cells[2].innerText)||'';var order=window.selectedSalesOrderId&&typeof salesOrder==='function'?salesOrder(selectedSalesOrderId):null;if(!order)return;var line=order.lines.find(function(x){var p=getProduct(x.productId);return p&&code.indexOf(p.sku)>=0});if(!line)return;if(line.bundleRole==='head'){tr.classList.add('bundle-line-head');var d=tr.cells[3];if(d)d.insertAdjacentHTML('afterbegin','<span class="bundle-pill">Bundle head</span><br>')}if(line.bundleRole==='component'){tr.classList.add('bundle-line-child');var c=tr.cells[3];if(c)c.insertAdjacentHTML('afterbegin','<span class="bundle-child-label">Component of '+esc(line.bundleParentName||'bundle')+'</span><br>')}})}
  var observer=new MutationObserver(function(){decorateRows()});observer.observe(document.documentElement,{childList:true,subtree:true});
})();
